<?php
namespace App\Core;
abstract class Controller { protected function view(string $view,array $data=[]):void{ extract($data); $viewFile=__DIR__.'/../Views/'.$view.'.php'; require __DIR__.'/../Views/layouts/app.php'; } protected function auth():void{ if(!current_user()) redirect('login'); } protected function requirePermission(string $module,string $action='ver'):void{ $this->auth(); if(($_SESSION['user']['rol']??'')==='Super Administrador') return; $perms=$_SESSION['permissions'][$module]??[]; if(empty($perms[$action])) { http_response_code(403); exit('Sin permisos'); } } protected function uploadImage(string $field,string $dir):?string{ if(empty($_FILES[$field]['name'])) return null; $cfg=App::config('image_mimes'); $tmp=$_FILES[$field]['tmp_name']; $mime=mime_content_type($tmp); if(!isset($cfg[$mime]) || $_FILES[$field]['size']>App::config('upload_max_bytes')) throw new \RuntimeException('Imagen inválida: use JPG, PNG o WEBP de máximo 3 MB.'); $name=bin2hex(random_bytes(12)).'.'.$cfg[$mime]; if(!is_dir(__DIR__.'/../../public/uploads/'.$dir)) mkdir(__DIR__.'/../../public/uploads/'.$dir,0775,true); move_uploaded_file($tmp,__DIR__.'/../../public/uploads/'.$dir.'/'.$name); return 'uploads/'.$dir.'/'.$name; } }
